const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

// ── Parameters ──────────────────────────────────────────────────
const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();
const frameDuration = parseFloat(params.FrameDuration) || 0.25;

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Generate Movie] No Cards found in Deck.json.');
}

// ── Filter cards ────────────────────────────────────────────────
const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error(
    '[Generate Movie] No cards matched filter: ' +
    JSON.stringify(testCardFilter) +
    '. Check that TestCardFilter matches a Card name in Deck.json.'
  );
}

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(
    deckDir,
    cardRef.File.replace(/\//g, path.sep)
  );

  // Read card JSON
  let cardRaw;
  try {
    cardRaw = JSON.parse(
      fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, '')
    );
  } catch (e) {
    console.warn('[Generate Movie] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({ card: cardName, status: 'failed', reason: 'Cannot read card file: ' + e.message });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards'))
    .replace(/\//g, path.sep);

  // ── Gather required fields ──────────────────────────────────

  // UprightImage from card-level Assets
  const uprightImageName = card.Assets && card.Assets.UprightImage;
  if (!uprightImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No Assets.UprightImage' });
    continue;
  }

  // Find upright record
  const uprightRecord = (card.records || []).find(r => r.Orientation === 'upright');
  if (!uprightRecord) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No upright record' });
    continue;
  }

  // Movie output name from record Assets
  const movieName = uprightRecord.Assets && uprightRecord.Assets.Movie;
  if (!movieName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No Movie in upright record Assets' });
    continue;
  }

  // CardImage from record Assets
  const cardImageName = uprightRecord.Assets && uprightRecord.Assets.CardImage;
  if (!cardImageName) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'No CardImage in upright record Assets' });
    continue;
  }

  // Check if movie already exists
  const movieOutputPath = path.join(cardDir, movieName);
  if (fs.existsSync(movieOutputPath)) {
    console.warn('[Generate Movie] Movie already exists for: ' + cardName + ', skipping.');
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'Movie already exists: ' + movieName });
    continue;
  }

  // ── Build ordered frame list ────────────────────────────────
  // Card name slug: replace whitespace with underscore, strip parens
  const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const frames = [];
  let missingFrame = false;

  // 1. UprightImage (first frame)
  const uprightImagePath = path.join(cardDir, uprightImageName);
  if (!fs.existsSync(uprightImagePath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'UprightImage not found: ' + uprightImageName });
    continue;
  }
  frames.push(uprightImagePath);

  // 2. FOCUST_UPRIGHT_XXX_00 through _05
  for (let i = 0; i <= 5; i++) {
    const nn = String(i).padStart(2, '0');
    const frameName = 'FOCUST_UPRIGHT_' + slug + '_' + nn + '.png';
    const framePath = path.join(cardDir, frameName);
    if (!fs.existsSync(framePath)) {
      results.skipped++;
      results.cards.push({ card: cardName, status: 'skipped', reason: 'Missing frame: ' + frameName });
      missingFrame = true;
      break;
    }
    frames.push(framePath);
  }
  if (missingFrame) continue;

  // 3. CardImage (middle frame)
  const cardImagePath = path.join(cardDir, cardImageName);
  if (!fs.existsSync(cardImagePath)) {
    results.skipped++;
    results.cards.push({ card: cardName, status: 'skipped', reason: 'CardImage not found: ' + cardImageName });
    continue;
  }
  frames.push(cardImagePath);

  // 4. FOCUS_UPRIGHT_XXX_07 through _14
  for (let i = 7; i <= 14; i++) {
    const nn = String(i).padStart(2, '0');
    const frameName = 'FOCUS_UPRIGHT_' + slug + '_' + nn + '.png';
    const framePath = path.join(cardDir, frameName);
    if (!fs.existsSync(framePath)) {
      results.skipped++;
      results.cards.push({ card: cardName, status: 'skipped', reason: 'Missing frame: ' + frameName });
      missingFrame = true;
      break;
    }
    frames.push(framePath);
  }
  if (missingFrame) continue;

  // ── Build ffmpeg concat file ────────────────────────────────
  const concatListPath = path.join(cardDir, '_concat_movie_' + slug + '.txt');

  // Each frame held for frameDuration seconds.
  // Last entry repeated without duration (ffmpeg concat demuxer convention).
  const lines = [];
  for (let i = 0; i < frames.length; i++) {
    const fwd = frames[i].replace(/\\/g, '/');
    lines.push("file '" + fwd + "'");
    lines.push('duration ' + frameDuration);
  }
  lines.push("file '" + frames[frames.length - 1].replace(/\\/g, '/') + "'");

  fs.writeFileSync(concatListPath, lines.join('\n') + '\n', 'utf8');

  // ── Run ffmpeg ──────────────────────────────────────────────
  // Video filter normalises all frames to 512x512:
  //   - 512x512 images pass through unchanged
  //   - UprightImage (680x1100) is scaled to cover then center-cropped
  const vf = 'scale=512:512:force_original_aspect_ratio=increase,crop=512:512';
  const concatFwd = concatListPath.replace(/\\/g, '/');
  const outputFwd = movieOutputPath.replace(/\\/g, '/');

  const cmd =
    'ffmpeg -y -f concat -safe 0' +
    ' -i "' + concatFwd + '"' +
    ' -vf "' + vf + '"' +
    ' -c:v mpeg2video -q:v 2 -pix_fmt yuv420p' +
    ' "' + outputFwd + '"';

  try {
    execSync(cmd, { encoding: 'utf8', timeout: 120000 });
  } catch (e) {
    results.failed++;
    results.cards.push({
      card: cardName,
      status: 'failed',
      reason: 'ffmpeg error: ' + (e.stderr || e.message)
    });
    try { fs.unlinkSync(concatListPath); } catch (_) {}
    continue;
  }

  // Cleanup temp concat file
  try { fs.unlinkSync(concatListPath); } catch (_) {}

  results.processed++;
  results.cards.push({
    card: cardName,
    status: 'generated',
    movie: movieOutputPath,
    frameCount: frames.length,
    frameDuration: frameDuration + 's',
    totalDuration: (frames.length * frameDuration).toFixed(2) + 's'
  });
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error(
    '[Generate Movie] No cards processed. ' +
    'Check TestCardFilter and Deck.json Cards array.'
  );
}

return [{ json: results }];
